"use strict";Game.setState=s=>{Game.state=s;Game.hitRects=[]};Game.toast=(s,t=1)=>{Game.message=s;Game.messageTime=t};Game.particle=function(x,y,c,n=14,pow=1){for(let i=0;i<n;i++)Game.particles.push({x,y,vx:Game.rnd(-170,170)*pow,vy:Game.rnd(-220,80)*pow,l:Game.rnd(.3,.75),c,s:Game.rnd(2,6)})};Game.startCinematic=function(type,name,quote,color){Object.assign(Game.bossFx,{cinema:2.25,cinemaType:type,cinemaName:name,cinemaQuote:quote,cinemaColor:color});Game.flash=.18;Game.shake=18;Game.particle(270,470,color,40,1.4)};Game.damageBoss=function(raw){const n=Math.max(1,Math.floor(raw-Game.boss.armor));Game.boss.hp=Math.max(0,Game.boss.hp-n);Game.score+=n*10;Game.bossFx.hit=.35;Game.shake=12;Game.flash=.08;Game.damageText.push({x:270,y:190,l:1.1,n,crit:n>=12000});Game.particle(270,190,"#fff",22,1.1);Game.beep(80,.15,"square",.06);if(Game.boss.hp<=0)Game.normalEnding()};Game.hurt=function(n){if(Game.barrierTurns>0)n=Math.ceil(n*.38);if(Game.talkRoute)n*=2;const p=Game.current();p.hp=Math.max(0,p.hp-Math.ceil(n));if(p.hp<=0){const next=Game.party.findIndex((q,i)=>q.hp>0&&!Game.permanentDead[i]);if(next<0)return Game.gameOver();Game.active=next}};Game.initSpace=function(){Game.stars=[];Game.nebulae=[];Game.meteors=[];for(let i=0;i<90;i++)Game.stars.push({x:Math.random()*540,y:Math.random()*960,z:1+Math.random()*3,v:8+Math.random()*28,a:.25+Math.random()*.75});for(let i=0;i<7;i++)Game.nebulae.push({x:Math.random()*540,y:Math.random()*750,r:80+Math.random()*180,v:2+Math.random()*8,h:190+Math.random()*120});for(let i=0;i<5;i++)Game.meteors.push({x:Math.random()*800-100,y:Math.random()*500,v:120+Math.random()*180})};